WITH cte_512 AS (SELECT BIT_XOR(ddm55.c8) AS col_1, VAR_POP(ddm55.c15) AS col_2 FROM t3 AS ddm55 WHERE (ddm55.c7 > 19)) SELECT DISTINCT UPPER(subq.group_concat_c8) AS col_1, STDDEV_POP(subq.bit_or_c15) AS col_1_2, ABS(subq.bit_or_c15) AS col_1_3, subq.bit_or_c15 AS bit_or_c15 FROM (SELECT s816.c13 AS c13, BIT_OR(s816.c15) AS bit_or_c15, GROUP_CONCAT(s816.c8 ORDER BY s816.c8) AS group_concat_c8 FROM t2 AS s816 WHERE (s816.c1 > 88) GROUP BY s816.c13 ORDER BY s816.c13 DESC LIMIT 8) AS subq WHERE subq.group_concat_c8 BETWEEN 16 AND 35 GROUP BY UPPER(subq.group_concat_c8), subq.bit_or_c15, ABS(subq.bit_or_c15), subq.bit_or_c15, subq.bit_or_c15, subq.bit_or_c15 ORDER BY subq.bit_or_c15 ASC

WITH cte_815 AS (SELECT COUNT(DISTINCT nyv37.c9) AS col_1, nyv37.c13 AS col_2, COUNT(nyv37.c14) AS col_3, (SELECT COUNT(DISTINCT s311.c5) AS subq_col FROM t2 AS s311) AS col_4 FROM t2 AS nyv37 WHERE ((CONCAT(nyv37.c4, nyv37.c4) = 'sample_5') OR (nyv37.c8 <> X'990363DF') OR (LOWER(nyv37.c6) = 'sample_61')) GROUP BY nyv37.c13), cte_531 AS (SELECT dfs1.c14 AS col_1, MAX(dfs1.c6) AS col_2, TAN(dfs1.c14) AS col_3 FROM t2 AS dfs1 GROUP BY dfs1.c14, TAN(dfs1.c14)) SELECT DISTINCT AVG(4) AS col_1, RANK() OVER (ORDER BY 1=1) AS col_1_2, subq.stddev_samp_col_4 AS stddev_samp_col_4, ABS(75) AS col_1_3, STD(34) AS col_1_4 FROM (SELECT STDDEV_SAMP(s661.col_4) AS stddev_samp_col_4, s661.col_1 AS col_1 FROM cte_815 AS s661 GROUP BY s661.col_1 ORDER BY s661.col_1 ASC) AS subq WHERE (subq.col_1 >= 86) GROUP BY subq.stddev_samp_col_4, subq.stddev_samp_col_4, subq.stddev_samp_col_4, ABS(75), subq.stddev_samp_col_4 ORDER BY subq.stddev_samp_col_4 DESC FOR UPDATE

WITH cte_789 AS (SELECT EXP(jro99.c4) AS col_1, ROW_NUMBER() OVER (PARTITION BY jro99.c3 ORDER BY jro99.c1 ASC) AS col_2 FROM t1 AS jro99), cte_972 AS (SELECT (SELECT s444.c2 AS subq_col FROM t1 AS s444 ORDER BY s444.c2 ASC LIMIT 1) AS col_1, STD(hvx46.c1) AS col_2 FROM t1 AS hvx46) SELECT DISTINCT ROUND(t3.c7, 0) AS col_1, BIT_AND(t3.c3) AS col_1_2, t3.c1 AS c1 FROM t3 AS t3 WHERE (t3.c14 NOT REGEXP '[a-z]+@[a-z]+\.[a-z]{2,3}') GROUP BY ROUND(t3.c7, 0), t3.c1, t3.c1, t3.c1 ORDER BY t3.c1 DESC

WITH cte_235 AS (SELECT COUNT(ivy16.c5) AS col_1, (SELECT AVG(s720.c15) AS subq_col FROM t3 AS s720) AS col_2, ivy16.c12 AS col_3, LENGTH(ivy16.c10) AS col_4 FROM t3 AS ivy16 WHERE ((UPPER(ivy16.c10) = 'sample_79') OR (DATE_FORMAT(ivy16.c4, 'HH24:MI:SS') = 'sample_62')) GROUP BY ivy16.c12, LENGTH(ivy16.c10)) (SELECT RANK() OVER (PARTITION BY hft74.col_2 ORDER BY hft74.col_3 DESC) AS col_1, VAR_SAMP(hft74.col_2) AS col_2, BIT_XOR(hft74.col_2) AS col_3, (SELECT MAX(s555.col_2) AS subq_col FROM cte_235 AS s555) AS col_4 FROM cte_235 AS hft74 WHERE hft74.col_1 IS NULL GROUP BY hft74.col_2, hft74.col_3) EXCEPT SELECT nxa33.c7 AS col_1, nxa33.c8 AS col_2, nxa33.c3 AS col_3, 47 AS col_4 FROM t3 AS nxa33 WHERE (nxa33.c6 < NULL)

WITH cte_383 AS (SELECT SUM(dun14.c1) AS col_1, LOG(dun14.c1) AS col_2 FROM t1 AS dun14 GROUP BY LOG(dun14.c1)) (SELECT ROUND(mpo74.c4, 1) AS col_1, (SELECT COUNT(DISTINCT 30) AS subq_col FROM t3 AS s679) AS col_2, DATE_FORMAT(fgg16.c13, 'DD-MON-YYYY') AS col_3 FROM t2 AS fgg16 LEFT JOIN t1 AS mpo74 ON fgg16.c1 IN (SELECT t1.c1 AS c1 FROM t1 AS t1 WHERE t1.c1 BETWEEN 1 AND 100) ORDER BY fgg16.c2 ASC LIMIT 3) INTERSECT SELECT DISTINCT aay79.col_2 AS col_1, 22 AS col_2, UPPER() AS col_3 FROM cte_383 AS aay79

WITH cte_377 AS (SELECT lpy68.c1 AS col_1, lpy68.c6 AS col_2 FROM t1 AS lpy68 WHERE lpy68.c5 NOT BETWEEN '2023-07-03 23:44:54' AND '2023-09-11 17:21:36') SELECT STD(t3.c2) AS col_1, CONCAT(t3.c12, 'str_6', t3.c14) AS col_1_2, t3.c10 AS c10, TAN(t3.c8) AS col_1_3, LOG(t3.c15) AS col_1_4 FROM t3 AS t3 WHERE (t3.c8 >= NULL) GROUP BY CONCAT(t3.c12, 'str_6', t3.c14), t3.c10, TAN(t3.c8), LOG(t3.c15) HAVING (STDDEV_POP(t3.c1) >= 2)

WITH cte_54 AS (SELECT (SELECT GROUP_CONCAT(s337.c5 ORDER BY s337.c5) AS subq_col FROM t1 AS s337) AS col_1, COUNT(DISTINCT xmx41.c5) AS col_2, TAN(xmx41.c4) AS col_3 FROM t1 AS xmx41 GROUP BY TAN(xmx41.c4)) SELECT DISTINCT subq.c13 AS c13, DENSE_RANK() OVER (ORDER BY 1=1) AS col_1, VAR_POP(58) AS col_1_2 FROM (SELECT s643.c13 AS c13, s643.c3 AS c3 FROM t3 AS s643 ORDER BY s643.c6 DESC LIMIT 10) AS subq GROUP BY subq.c13, subq.c13, subq.c13 ORDER BY subq.c13 ASC

WITH cte_615 AS (SELECT (SELECT s873.c6 AS subq_col FROM t1 AS s873 ORDER BY s873.c6 ASC LIMIT 1) AS col_1, STDDEV_SAMP(lyi33.c4) AS col_2 FROM t1 AS lyi33), cte_751 AS (SELECT bvi91.c4 AS col_1, EXP(bvi91.c8) AS col_2, LOG(bvi91.c2) AS col_3 FROM t3 AS bvi91) SELECT DISTINCT COUNT(DISTINCT t1.c2) AS col_1, t1.c1 AS c1, SUBSTRING(t1.c6, 13, 8) AS col_1_2, t1.c5 AS c5 FROM t1 AS t1 WHERE t1.c5 BETWEEN '2023-01-01' AND '2023-01-01' GROUP BY t1.c1, t1.c5, SUBSTRING(t1.c6, 13, 8), t1.c5, t1.c5, t1.c5 HAVING (BIT_AND(t1.c4) = 8) ORDER BY t1.c5 DESC

WITH cte_158 AS (SELECT VAR_POP(fuo82.c1) AS col_1, STDDEV(fuo82.c2) AS col_2, SUM(DISTINCT fuo82.c6) AS col_3 FROM t3 AS fuo82 WHERE (fuo82.c7 < 90)) (SELECT SUM(DISTINCT zvf99.c8) AS col_1, RANK() OVER (PARTITION BY zvf99.c12 ORDER BY zvf99.c14 ASC) AS col_2, CONCAT(zvf99.c14, bqy98.c6) AS col_3, bqy98.c1 AS col_4 FROM t3 AS zvf99 RIGHT JOIN t1 AS bqy98 ON (zvf99.c6 = bqy98.c4) GROUP BY zvf99.c12, zvf99.c14, CONCAT(zvf99.c14, bqy98.c6), bqy98.c1) UNION SELECT DISTINCT ocy41.c1 AS col_1, ocy41.c3 AS col_2, ocy41.c7 AS col_3, ocy41.c2 AS col_4 FROM t2 AS ocy41

WITH cte_873 AS (SELECT VAR_SAMP(upq44.c2) AS col_1, upq44.c6 AS col_2, BIT_OR(upq44.c2) AS col_3 FROM t2 AS upq44 WHERE ((TAN(upq44.c3) = 75) OR (LOG(upq44.c15) <> 37)) GROUP BY upq44.c6) SELECT MIN(qfg73.c4) AS col_1, AVG(qfg73.c4) AS col_2 FROM t1 AS qfg73 WHERE ((ABS(qfg73.c1) > 8) AND (DATE_FORMAT(qfg73.c5, '%Y-%m-%d %H:%i:%s') = 'sample_65') AND (LENGTH(qfg73.c2) > 9)) UNION ALL SELECT azu33.c6 AS col_1, azu33.c15 AS col_2 FROM t3 AS azu33 UNION ALL SELECT DISTINCT xzf68.c15 AS col_1, xzf68.c9 AS col_2 FROM t3 AS xzf68

WITH cte_13 AS (SELECT VAR_SAMP(ijg37.c1) AS col_1, SUBSTRING(ijg37.c6, 5, 5) AS col_2 FROM t2 AS ijg37 WHERE ((LOWER(ijg37.c10) = 'sample_19') OR (ABS(ijg37.c15) <> 97)) GROUP BY SUBSTRING(ijg37.c6, 5, 5)) SELECT DISTINCT VAR_SAMP(t3.c2) AS col_1, ROUND(t2.c14, 1) AS col_1_2, t2.c3 AS c3 FROM t2 AS t2 CROSS JOIN t3 AS t3 ON (t3.c3 = t2.c1) GROUP BY ROUND(t2.c14, 1), t2.c3, t2.c3, t2.c3 ORDER BY t2.c3 ASC